{
    size ??= _defaultSize;
    if (_gcStrategy.CanStartNoGCRegion())
    {
        FailCause failCause = FailCause.None;
        try
        {
            if (!System.GC.TryStartNoGCRegion(size.Value, true))
            {
                failCause = FailCause.GCFailedToStartNoGCRegion;
            }
        }
